#include "kvant/backtest/multi_asset.hpp"
#include <algorithm>
#include <cmath>
#include <stdexcept>
namespace kvant::backtest {Result run_multi_asset(std::vector<Bar>b,const Targets&t,const Config&c){if(c.initial_cash<=0||c.max_participation<=0||c.max_participation>1)throw std::invalid_argument("config");std::sort(b.begin(),b.end(),[](auto&a,auto&z){return a.time<z.time||(a.time==z.time&&a.symbol<z.symbol);});Result out;double cash=c.initial_cash,equity=cash,previous=equity;std::map<std::string,double>pos,last;std::size_t i=0;while(i<b.size()){auto time=b[i].time;std::size_t j=i;while(j<b.size()&&b[j].time==time)++j;for(auto k=i;k<j;++k){auto&x=b[k];if(x.split_factor<=0||x.open<=0||x.close<=0||x.adv<=0)throw std::invalid_argument("bar");pos[x.symbol]*=x.split_factor;cash+=pos[x.symbol]*x.cash_dividend;last[x.symbol]=x.open;if(x.delisted&&pos[x.symbol]!=0){cash+=pos[x.symbol]*x.open;pos[x.symbol]=0;}}equity=cash;for(auto&[s,q]:pos)if(last.count(s))equity+=q*last[s];double turnover=0;if(auto it=t.find(time);it!=t.end()){for(auto&o:it->second){auto bi=std::find_if(b.begin()+i,b.begin()+j,[&](auto&x){return x.symbol==o.symbol;});if(bi==b.begin()+j)continue;double desired=o.target_weight*equity/bi->open,qty=desired-pos[o.symbol],cap=c.max_participation*bi->adv;qty=std::clamp(qty,-cap,cap);if(std::abs(qty)<1e-12)continue;double sign=qty>0?1:-1,impact=bi->open*c.impact_coefficient*std::sqrt(std::abs(qty)/bi->adv),price=bi->open+sign*(bi->spread/2+impact),fee=std::max(c.minimum_commission,std::abs(qty)*c.commission_per_unit);cash-=qty*price+fee;pos[o.symbol]+=qty;turnover+=std::abs(qty*price);out.fills.push_back({time,o.symbol,qty,price,fee,impact});}}
equity=cash;double gross=0;for(auto k=i;k<j;++k){last[b[k].symbol]=b[k].close;}for(auto&[s,q]:pos)if(last.count(s)){equity+=q*last[s];gross+=std::abs(q*last[s]);}out.days.push_back({time,equity,equity/previous-1,cash,gross,turnover/equity});previous=equity;i=j;}out.positions=std::move(pos);return out;}}
